class SubMenus extends BaseSubMenus
{
    public function save(Doctrine_Connection $conn = null)
    {
		if(strlen($this->getMaxDuration()) == 0){
			$this->setMaxDuration(0);
		}
		if(!$this->getOrderNo()){
			$this->setOrderNo($this->getId());
		}
		if(!$this->getChangeFieldElement()){
			$this->setChangeFieldElement(0);
		}
		if(!$this->getChangeFieldElementForm_1()){
			$this->setChangeFieldElementForm_1(0);
		}
		if(!$this->getChangeFieldElementForm_2()){
			$this->setChangeFieldElementForm_2(0);
		}
		if(!$this->getChangeFieldElementForm_3()){
			$this->setChangeFieldElementForm_3(0);
		}
		if(!$this->getChangeFieldElementForm_4()){
			$this->setChangeFieldElementForm_4(0);
		}
		if(!$this->getChangeFieldElementForm_5()){
			$this->setChangeFieldElementForm_5(0);
		}
        parent::save($conn);

        $translation = new Translation();
        $translation->setTranslation('submenus','title',parent::_get("id"), parent::_get("title"));
    }
	public function getTitle()
	{
		$translation = new Translation();
		if($translation->getTranslation('submenus','title',$this->getId()) && $translation->getTranslation('submenus','title',$this->getId()) != "")
        {
          	return $translation->getTranslation('submenus','title',$this->getId());
        }
        else
        {
        	return parent::_get("title");
        }
	}
	//OTB ADD
	public function getNoOfApplcations()
	{
		$q=Doctrine_Query::create()
			->from('FormEntry e')
			->innerJoin('e.Stage m')
			->where('e.deleted_status =? and e.parent_submission =? and e.approved =?',array(0,0,$this->getId()));
		return $q->count();
	}
}
